spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var stage = 1;
    if (progress >= 0.25 && progress < 0.54) stage = 2;
    else if (progress >= 0.54 && progress < 0.79) stage = 3;
    else if (progress >= 0.79) stage = 4;

    var midY = H / 2 - 35;
    var startX = W / 2 - 70;
    var spacing = 10;
    var radius = 4;

    // Draw 6 Red and 9 Blue circles
    if (stage <= 2) {
      // Red circles (0 to 5)
      for (var i = 0; i < 6; i++) {
        ctx.fillStyle = '#EF4444';
        ctx.beginPath();
        ctx.arc(startX + i * spacing, midY, radius, 0, Math.PI * 2);
        ctx.fill();
      }
      // Blue circles (6 to 14)
      for (var j = 0; j < 9; j++) {
        ctx.fillStyle = '#3B82F6';
        ctx.beginPath();
        ctx.arc(startX + (6 + j) * spacing, midY, radius, 0, Math.PI * 2);
        ctx.fill();
      }

      // Stage 2: Draw grouping boxes around every 3 elements
      if (stage === 2) {
        ctx.strokeStyle = 'rgba(243, 244, 246, 0.6)';
        ctx.lineWidth = 1.5;
        for (var k = 0; k < 5; k++) {
          var gx = startX + k * 3 * spacing + spacing - 5;
          ctx.strokeRect(gx - 8, midY - 10, 26, 20);
        }
      }
    } else {
      // Stage 3 & 4: Draw 2 big Red circles and 3 big Blue circles
      var bigRadius = 12;
      var bigStartX = W / 2 - 50;
      var bigSpacing = 25;

      // Red big circles (0 to 1)
      for (var i = 0; i < 2; i++) {
        ctx.fillStyle = '#EF4444';
        ctx.beginPath();
        ctx.arc(bigStartX + i * bigSpacing, midY, bigRadius, 0, Math.PI * 2);
        ctx.fill();

        ctx.fillStyle = '#FFFFFF';
        ctx.font = 'bold 9px -apple-system, sans-serif';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText('3', bigStartX + i * bigSpacing, midY);
      }
      // Blue big circles (2 to 4)
      for (var j = 0; j < 3; j++) {
        ctx.fillStyle = '#3B82F6';
        ctx.beginPath();
        ctx.arc(bigStartX + (2 + j) * bigSpacing, midY, bigRadius, 0, Math.PI * 2);
        ctx.fill();

        ctx.fillStyle = '#FFFFFF';
        ctx.font = 'bold 9px -apple-system, sans-serif';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText('3', bigStartX + (2 + j) * bigSpacing, midY);
      }
    }

    // Bottom text explanations
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.font = 'bold 15px -apple-system, sans-serif';
    ctx.fillStyle = '#F3F4F6';

    if (stage === 1) {
      ctx.fillText('Ratio = 6 : 9', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('6 red circles compared to 9 blue circles.', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillStyle = '#60A5FA';
      ctx.fillText('Divide by Common Factor (3)', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Both 6 and 9 are multiples of 3. Group them into groups of 3.', W / 2, H - 22);
    } else if (stage === 3) {
      ctx.fillStyle = '#10B981';
      ctx.fillText('Forming 2 Red and 3 Blue Clusters', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Each large circle represents a cluster of 3 original circles.', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#10B981';
      ctx.fillText('Simplified Form = 2 : 3', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('6 ÷ 3 : 9 ÷ 3 = 2 : 3. No common factors remain.', W / 2, H - 22);
    }
  }
};
